<template>
  <div class="w-full" :data-cy="`scorecard-criteria-slider-${index}`">
    <label v-if="label" for="label" class="block text-sm font-medium text-gray-700">{{ label }}</label>
    <div class="mt-1">
      <input
        :id="id"
        :class="`range range-md ox-slider range-criteria-color-${index} ox-slidery ${sliderClass} ${oxScoredClass}`"
        type="range"
        :value="disabled ? 0 : score"
        :name="label"
        :min="min"
        :max="max"
        :disabled="disabled"
        @input="inputChanged"
        @click="inputChanged"
      />
    </div>
  </div>
</template>

<script>
export default {
  props: {
    score: {
      type: Number,
      default: 0,
    },
    oxgptScoredLast: {
      type: Boolean,
      default: false,
    },
    label: {
      type: String,
      required: false,
      default: "",
    },
    min: {
      type: Number,
      default: 0,
    },
    max: {
      type: Number,
      default: 100,
    },
    id: {
      type: String,
      default: "",
    },
    data_cy: {
      type: String,
      default: "",
    },
    index: {
      type: Number,
      default: 1,
    },
    sliderClass: {
      type: String,
      default: "",
    },
    disabled: {
      type: Boolean,
      default: false,
    },
    enableOxScoring: {
      type: Boolean,
      default: false,
    },
    initialOxScore: {
      type: Number,
      default: -1,
    },
  },
  emits: ["update:score", "update:oxgptScoredLast"],
  computed: {
    midRange() {
      return Math.round(this.min + this.max / 2);
    },
    oxScoredClass() {
      if (!this.enableOxScoring) {
        return "range-primary";
      }
      // return this.changed? this.score === this.initialOxScore ? 'ox_scored': '';
      return this.oxgptScoredLast ? "ox_scored range-info" : "range-primary";
    },
  },
  methods: {
    inputChanged(event) {
      this.$emit("update:score", Number(event.target.value));
      this.$emit("update:oxgptScoredLast", false);
      // this.oxgptScoredLast = false;
    },
  },
};
</script>
