  -webkit-appearance: none;
  display: none;
}

input[type="range"].range-info.ox_scored {
  -webkit-appearance: none;
  /*  width: 100%;*/
  /*  height: 25px;*/
  /*  background: #ddd;*/
  outline: none;
}

input[type="range"].range-info.ox_scored::-webkit-slider-thumb {
  -webkit-appearance: none;
  appearance: none;
  background-image: url("data:image/png;base64,");
  background-size: cover;
  border: 1px solid #fff;
  @apply p-2;
  /*width: 50px;
  height: 50px;*/

  cursor: pointer;
}

input[type="range"].range-info.ox_scored::-moz-range-thumb {
  background-image: url("data:image/png;base64,");
  background-size: cover;
  border: 1px solid #fff;
  @apply p-2;
  /*width: 50px;
  height: 50px;*/

  cursor: pointer;
}

